    this.modelLoader = new ModelLoader();
    this.transformMode = 'translate';
    this.undoStack = [];
    this.redoStack = [];
    this.clock = new THREE.Clock();
    this.debug = true;

    this.initScene();
    this.initCamera();
    this.initRenderer();
    this.initLights();
