      model.position.copy(position);
      this.scene.add(model);
      this.objects.push(model);
      this.addToUndoStack({ type: 'add', object: model, properties: this.getObjectState(model) });
      this.selectObject(model);
    });
  }

  duplicateObject(object) {
    if (!object) return;
    this.modelLoader.duplicate(object, (clone) => {
      clone.position.x += 0.5;
      clone.position.z += 0.5;
      clone.userData = { ...object.userData, isModelRoot: true, selectable: true };
      this.objects.push(clone);
      this.scene.add(clone);
      this.addToUndoStack({ type: 'add', object: clone, properties: this.getObjectState(clone) });
      this.selectObject(clone);
    });
  }

  removeObject(object) {
    if (!object) return;
    this.addToUndoStack({ type: 'remove', object: object, properties: this.getObjectState(object) });
    if (this.selectedObject === object) this.deselectObject();
