  }

  updateObjectState(object) {
    this.addToUndoStack({ type: 'transform', object: object, properties: this.getObjectState(object) });
  }

  addToUndoStack(action) {
    this.undoStack.push(action);
    this.redoStack = [];
  }

  undo() {
    if (this.undoStack.length === 0) return;
    const action = this.undoStack.pop();
    this.redoStack.push(action);
    switch (action.type) {
      case 'add':
        this.scene.remove(action.object);
        this.objects = this.objects.filter(obj => obj !== action.object);
        if (this.selectedObject === action.object) this.deselectObject();
        break;
      case 'remove':
        this.scene.add(action.object);
        this.objects.push(action.object);
        break;
      case 'transform':
        Object.assign(action.object, action.properties);
